parameters.jsCode:
const prevData = $('Format Classification').first().json;
const microserviceResponse = $input.first().json;

const labelColorMap = {
  VERIFIED_TRUE:       'green',
  PARTIALLY_TRUE:      'yellow',
  MISLEADING:          'orange',
  FALSE:               'red',
  UNVERIFIED:          'gray',
  MANIPULATED_CONTENT: 'darkred'
};

// Fallback: microservice unavailable
if (!microserviceResponse.success) {
  return [{
    json: {
      mode:        'normal_fallback',
      status:      'COMPLETED',
      note:        'Microservice failed — returning agent classification.',
      post_id:     prevData.post_id,
      label:       prevData.label,
      label_color: prevData.label_color,
      label_score: prevData.label_score,
      confidence:  prevData.confidence,
      reasoning:   prevData.reasoning
    }
  }];
}

const trustCard   = microserviceResponse.trust_card;
const baseScore   = prevData.label_score;
const sourceScore = trustCard.detailed_scores.source ?? 50;

// Weighted deep score: agent classification (40%) + forensics (60%)
const deepScore =
  baseScore                            * 0.40 +
  trustCard.detailed_scores.provenance * 0.15 +
  trustCard.detailed_scores.content    * 0.25 +
  trustCard.detailed_scores.context    * 0.15 +
  sourceScore                          * 0.05;

// Map numeric deep score back to a label
let deepLabel;
if      (deepScore >= 80) deepLabel = 'VERIFIED_TRUE';
else if (deepScore >= 60) deepLabel = 'PARTIALLY_TRUE';
else if (deepScore >= 40) deepLabel = 'UNVERIFIED';
else if (deepScore >= 20) deepLabel = 'MISLEADING';
else                       deepLabel = 'FALSE';

// Forensics override: manipulation always wins
if (
  trustCard.content_analysis?.manipulation_detected ||
  trustCard.content_analysis?.ai_generated
) {
  deepLabel = 'MANIPULATED_CONTENT';
}

return [{
  json: {
    mode:        'deep',
    status:      'COMPLETED',
    post_id:     prevData.post_id,
    label:       deepLabel,
    label_color: labelColorMap[deepLabel],
    label_score: Math.round(deepScore),
    base_label:  prevData.label,
    confidence:  trustCard.confidence,
    summary_bullets: trustCard.summary_bullets,
    forensics: {
      manipulation_detected: trustCard.content_analysis.manipulation_detected,
      ai_generated:          trustCard.content_analysis.ai_generated,
      has_metadata:          trustCard.provenance.has_exif || trustCard.provenance.has_c2pa,
      suspicious_signs:      trustCard.provenance.suspicious_signs,
      ela_suspicious:        trustCard.content_analysis.ela_suspicious
    },
    reasoning:          prevData.reasoning,
    processing_time_ms: microserviceResponse.processing_time_ms
  }
}];

// Parse the agent's JSON output and reshape it for downstream nodes
const agentOutput = $input.first().json.output || '';
const extractData = $('Extract Content').first().json;

let parsed;

try {
  const clean = agentOutput.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  const match = agentOutput.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : {};
}

return [
  {
    json: {...parsed,...extractData}
  }
];

const post = $input.first().json;
return [{
  json: {
    post_id: $('Code in JavaScript').first().json.post_id || null,
    caption: $('Code in JavaScript').first().json.caption || '',
    alt_text: $('Code in JavaScript').first().json.alt_text || null,
    deep_mode: $('Code in JavaScript').first().json.deep_mode || false,
    claimed_date: $('Code in JavaScript').first().json.claimed_date || null,
    claimed_location :  $('Code in JavaScript').first().json.claimed_location || null,
    media_url : $('Code in JavaScript').first().json.media_url || null,
  }
}];

